export type Cell = [number, number];

type CellKey = string;

const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;

const fromKey = (key: CellKey): Cell => {
  const [x, y] = key.split(",");
  return [Number(x), Number(y)];
};

const countNeighbors = (cells: Cell[]): Map<CellKey, number> => {
  const counts = new Map<CellKey, number>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighborKey = toKey([x + dx, y + dy]);
        counts.set(neighborKey, (counts.get(neighborKey) ?? 0) + 1);
      }
    }
  }
  return counts;
};

const survives = (isAlive: boolean, neighborCount: number): boolean =>
  isAlive ? neighborCount === 2 || neighborCount === 3 : neighborCount === 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCells = new Set(cells.map(toKey));
  const neighborCounts = countNeighbors(cells);

  const survivors: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    if (survives(liveCells.has(key), count)) {
      survivors.push(fromKey(key));
    }
  }
  return survivors;
}
